int winner ( vector<int> a , int n , int k ) {
    int best = 0;
    int times = 0;
    if ( k >= n - 1 ) {
        return n;
    }
    for ( int i = 0; i < n; i++ ) {
        if ( a[i] > best ) {
            best = a[i];
            if ( i == true ) {
                times = 1;
            }
            else {
                times += 1;
            }
            if ( times >= k ) {
                return best;
            }
        }
    }
    return best;
}

