int numOfIncSubseqOfSizeK (vector<int> arr, int n, int k) {
    vector<vector<int> > dp(k, vector<int>(n));
    for (int i = 0; i < n; i++) {
        dp[0][i] = 1;
    }
    for (int l = 1; l < k; l++) {
        for (int i = l; i < n; i++) {
            dp[l][i] = 0;
            for (int j = l - 1; j < i; j++) {
                if (arr[j] < arr[i]) {
                    dp[l][i] += dp[l - 1][j];
                }
            }
        }
    }
    int Sum = 0;
    for (int i = k - 1; i < n; i++) {
        Sum += dp[k - 1][i];
    }
    return Sum;
}

